local function registerCallBack()
    local observable = EventObservable.new()
    observable:registerDataCallBack("TowerList", function(data)
        GamePlayer:Instance():setOwnedTowerList(data)
    end, JsonBuilderProcessor)

    observable:registerDataCallBack("GetNewTower", function(data)
        GamePlayer:Instance():onGetNewTower(data)
    end, JsonBuilderProcessor)

    observable:registerDataCallBack("SkinInfo", function(data)
        GamePlayer:Instance():setSkinInfo(data)
    end, JsonBuilderProcessor)

    observable:registerDataCallBack("EquipSkin", function(data)
        GamePlayer:Instance():EquipSkin(data)
    end, JsonBuilderProcessor)

    observable:registerDataCallBack("ExchangeRate", function(data)
        GamePlayer:Instance():setExchangeRate(data)
    end, DataBuilderProcessor)

    observable:registerDataCallBack("Countdown", function(data)
        GamePlayer:Instance():setCountdownEffect(data)
    end, DataBuilderProcessor)

    observable:registerDataCallBack("PlayerNum", function(data)
        GamePlayer:Instance():setTeamAreaPlayerNum(data)
    end, DataBuilderProcessor)
end

GameListener = {}

function GameListener:init()
    registerCallBack()
    BaseListener.registerCallBack(GameReadyEvent, self.onGameReady)
    BaseListener.registerCallBack(GameDestroyEvent, self.onGameDestroy)

    Listener.registerCallBack(SumRechargeCreateItemsEvent, function()
        local defineContentWidth = 925
        local defineContentHeight = 512
        local defineRewardWidth = 105

        local name = string.gsub(GUISumRechargeLayout.__name, ".json", "-")
        local llContent = GUISumRechargeLayout:getChildWindow(name .. "Content", GUIType.Layout)
        local btnClose = GUISumRechargeLayout:getChildWindow(name .. "Close", GUIType.Button)
        local totalWidth = btnClose:GetPixelSize().x
        if totalWidth < defineContentWidth then
            defineContentHeight = math.floor(defineContentHeight / defineContentWidth * totalWidth * 0.9)
            defineRewardWidth = math.floor(defineRewardWidth / defineContentWidth * totalWidth * 0.9)
            defineContentWidth = math.floor(totalWidth * 0.9)
        end
        llContent:SetWidth({ 0, defineContentWidth })
        llContent:SetHeight({ 0, defineContentHeight })
        GUISumRechargeLayout:setRewardWidth(defineRewardWidth)
        ---禁止奖励窗滑动
        GUISumRechargeLayout.gvRewards.root:SetMoveAble(false)

        ---调整首充UI Title
        local config = SumRechargeConfig:getSumRecharge(GUISumRechargeLayout.currentId)
        GUISumRechargeLayout:getChildWindow(name .. "Title_c", GUIType.StaticText):SetText(Lang:getString(config.TitleLang))
        GUISumRechargeLayout:getChildWindow(name .. "Title_c_c", GUIType.StaticText):SetText(Lang:getString(config.TitleLang))
        return true
    end)
    Listener.registerCallBack(GoRechargeEvent, self.onGoRecharge)
end

function GameListener.onGameReady()
    TextureAtlasRegister.Instance():addTextureAtlas("skin_price.json", "")
    TextureAtlasRegister.Instance():addTextureAtlas("tower_defense_map.json", "")
    GameConfig:init()
    require "ui.GUIFactory"

    LuaTimer:schedule(function()
        BgmUtil:startBgm(10051)
    end, 1000)

    if Platform.isWindow() == false then
        GamePlayer:Instance().poleControlState = Blockman.Instance().m_gameSettings.usePole
        local isUsePole = ClientHelper.getBoolForKey(tostring(GamePlayer:Instance().userId) .. ("isTDUsePole"), true)
        if isUsePole == true or isUsePole == nil then
            Utility.refreshPoleControlState(1)
        else
            Utility.refreshPoleControlState(0)
        end
    end

    TextureAtlasRegister.Instance():addTextureAtlas("tower_defense_float_number.json", "")
    for i = 0, 9 do
        WorldImageRender.Instance():addImageRender("tower_defense_float_number.json", 6, tostring(i), string.format("num%d", i))
    end
end

function GameListener.onGameDestroy()
    if not Blockman.Instance() or not GamePlayer:Instance() then
        return
    end
    if Platform.isWindow() == false then
        local isUsePole = Blockman.Instance().m_gameSettings.usePole
        if isUsePole == 1 then
            ClientHelper.putBoolForKey(tostring(GamePlayer:Instance().userId) .. ("isTDUsePole"), true)
        else
            ClientHelper.putBoolForKey(tostring(GamePlayer:Instance().userId) .. ("isTDUsePole"), false)
        end
        Utility.refreshPoleControlState(GamePlayer:Instance().poleControlState)
    end
end
